        // Assert
        card.Id.Should().NotBe(Guid.Empty);
        card.UserId.Should().Be(_testUserId);
        card.BankName.Should().Be(_testBankName);
        card.BankCardNumber.Should().Be(_testBankCardNumber);
        card.AccountName.Should().Be(_testAccountName);
        card.IsDefault.Should().BeFalse();
        card.CreatedAt.Should().Be(_testNow);
        card.UpdatedAt.Should().Be(_testNow);
    }

    [Fact]
    public void Create_WithEmptyUserId_ShouldThrowDomainException()
    {
        // Act
        var act = () => UserBankCard.Create(
            Guid.Empty,
            _testBankName,
            _testBankCardNumber,
            _testAccountName,
