    [Fact]
    public void SetAsDefault_ShouldSetIsDefaultToTrue()
    {
        // Arrange
        var card = CreateUserBankCard();
        var newNow = _testNow.AddHours(1);

        // Act
        card.SetAsDefault(newNow);

        // Assert
        card.IsDefault.Should().BeTrue();
        card.UpdatedAt.Should().Be(newNow);
    }

    [Fact]
    public void UnsetAsDefault_ShouldSetIsDefaultToFalse()
    {
        // Arrange
        var card = CreateUserBankCard();
        card.SetAsDefault(_testNow);
        var newNow = _testNow.AddHours(1);

        // Act
        card.UnsetAsDefault(newNow);

        // Assert
        card.IsDefault.Should().BeFalse();
        card.UpdatedAt.Should().Be(newNow);
